-- 确认这 65 个候选里,哪些【已经在库】(剩下的才是真·新品要导入)。
-- ① 已在库的(这些不用管):
select supplier_sku, name from products
where supplier ilike 'trends%' and supplier_sku in ('133808','133810','133807','133809','133815','133814','133813','133817','133818','133816','129615','129665','129697','129700','129699','129730','129726','133657','133656','133655','133407','133406','133405','133404','133403','133402','133401','133400','133399','133398','133397','133396','133395','133394','133393','133392','133391','129729','129728','133563','133562','129704','129725','129724','129723','129722','129721','129621','129702','133812','133811','129578','129577','129734','129735','129580','129689','129698','129490','128808','110593','110916','124422','127014','127326')
order by supplier_sku;

-- ② 想直接看"库里没有的"(=真新品),用这个:
--   把候选 code 建成临时集合,反查不在 products 里的。
with cand(code) as (values ('133808'),('133810'),('133807'),('133809'),('133815'),('133814'),('133813'),('133817'),('133818'),('133816'),('129615'),('129665'),('129697'),('129700'),('129699'),('129730'),('129726'),('133657'),('133656'),('133655'),('133407'),('133406'),('133405'),('133404'),('133403'),('133402'),('133401'),('133400'),('133399'),('133398'),('133397'),('133396'),('133395'),('133394'),('133393'),('133392'),('133391'),('129729'),('129728'),('133563'),('133562'),('129704'),('129725'),('129724'),('129723'),('129722'),('129721'),('129621'),('129702'),('133812'),('133811'),('129578'),('129577'),('129734'),('129735'),('129580'),('129689'),('129698'),('129490'),('128808'),('110593'),('110916'),('124422'),('127014'),('127326'))
select c.code from cand c
left join products p on p.supplier_sku=c.code and p.supplier ilike 'trends%'
where p.id is null
order by c.code;
